select distinct m.* FROM sys_menu m JOIN sys_role_menu rm ON rm.menu_id = m.menu_id JOIN ( -- ① 来自岗位的角色 SELECT srp.role_id FROM sys_user_post sup JOIN sys_role_post srp ON srp.post_id = sup.post_id WHERE sup.user_id = #{userId}
UNION
-- ② 来自用户直授的角色（可选） SELECT sur.role_id FROM sys_user_role sur WHERE sur.user_id = #{userId}) r ON r.role_id = rm.role_id ${ew.getCustomSqlSegment}

SELECT DISTINCT m.menu_id FROM sys_menu m JOIN sys_role_menu rm ON rm.menu_id = m.menu_id JOIN (SELECT srp.role_id FROM sys_user_post sup JOIN sys_role_post srp ON srp.post_id = sup.post_id WHERE sup.user_id = #{userId}
UNION
SELECT sur.role_id FROM sys_user_role sur WHERE sur.user_id = #{userId}) r ON r.role_id = rm.role_id WHERE m.status = '0'

SELECT DISTINCT m.perms FROM sys_menu m JOIN sys_role_menu rm ON rm.menu_id = m.menu_id JOIN (SELECT srp.role_id FROM sys_user_post sup JOIN sys_role_post srp ON srp.post_id = sup.post_id WHERE sup.user_id = #{userId}
UNION
SELECT sur.role_id FROM sys_user_role sur WHERE sur.user_id = #{userId}) r ON r.role_id = rm.role_id WHERE m.perms IS NOT NULL AND m.perms != '' AND m.status = '0'

select distinct m.* FROM sys_menu m JOIN sys_role_menu rm ON rm.menu_id = m.menu_id JOIN ( -- ① 来自岗位的角色 SELECT srp.role_id FROM sys_user_post sup JOIN sys_role_post srp ON srp.post_id = sup.post_id WHERE sup.user_id = #{userId}
UNION
-- ② 来自用户直授的角色（可选） SELECT sur.role_id FROM sys_user_role sur WHERE sur.user_id = #{userId} ) r ON r.role_id = rm.role_id ${ew.getCustomSqlSegment}
